<!doctype html><html><head><meta charset="utf-8"><title>{{ $receipt->receipt_number }}</title><style>body{font-family:Arial,sans-serif;color:#111;margin:30px}.top{display:flex;justify-content:space-between;border-bottom:2px solid #111;padding-bottom:15px}.box{margin-top:20px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:20px}.row{display:flex;justify-content:space-between;border-bottom:1px solid #eee;padding:8px 0}.btn{padding:8px 14px;border:1px solid #111;background:white;cursor:pointer}@media print{.no-print{display:none}}</style></head><body><button class="btn no-print" onclick="window.print()">Print</button><div class="top"><div><h1>Receipt</h1><p>{{ $receipt->receipt_number }}</p></div><div><p>Date: {{ optional($receipt->receipt_date)->format('d M Y') }}</p><p>Status: {{ $receipt->status }}</p></div></div><div class="grid box"><div><h3>Received From</h3><p>{{ $receipt->received_from ?: optional($receipt->customer)->name ?: optional($receipt->order)->customer_name }}</p></div><div><h3>Reference</h3><p>Order: {{ optional($receipt->order)->order_number ?: '-' }}</p><p>Invoice: {{ optional($receipt->invoice)->invoice_number ?: '-' }}</p></div></div><div class="box"><div class="row"><strong>Amount</strong><span>Rs. {{ number_format($receipt->amount,2) }}</span></div><div class="row"><strong>Method</strong><span>{{ strtoupper($receipt->payment_method ?: '-') }}</span></div><div class="row"><strong>Gateway</strong><span>{{ $receipt->payment_gateway ?: '-' }}</span></div><div class="row"><strong>Transaction ID</strong><span>{{ $receipt->transaction_id ?: '-' }}</span></div><div class="row"><strong>Received By</strong><span>{{ $receipt->received_by ?: '-' }}</span></div></div><div class="box"><p><strong>Notes:</strong> {{ $receipt->notes }}</p></div></body></html>
